description:
Implement JinjaRenderMethod - the callable object returned by value.render that enables value.render('json').

Location: crates/baml-bridge/src/prompt/jinja.rs

```rust
/// Callable object for value.render('style') syntax
pub struct JinjaRenderMethod {
    pv: PromptValue,
}

impl std::fmt::Debug for JinjaRenderMethod {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write\!(f, 'JinjaRenderMethod({})', self.pv.path)
    }
}

impl std::fmt::Display for JinjaRenderMethod {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write\!(f, '<render method>')
    }
}

impl Object for JinjaRenderMethod {
    fn call(
        self: &Arc<Self>,
        _state: &minijinja::State<'_, '_>,
        args: &[Value],
    ) -> Result<Value, minijinja::Error> {
        // Parse style argument
        let style = args.first()
            .and_then(|v| v.as_str())
            .ok_or_else(|| minijinja::Error::new(
                minijinja::ErrorKind::InvalidOperation,
                'render() requires a style string argument'
            ))?;

        // Call the render pipeline with explicit style override
        let result = self.pv.world.render_prompt_value(&self.pv, Some(style))
            .map_err(|e| minijinja::Error::new(
                minijinja::ErrorKind::InvalidOperation,
                e.message.clone()
            ))?;

        Ok(Value::from(result.text))
    }
}

impl JinjaPromptValue {
    fn render_method(&self) -> Value {
        Value::from_object(JinjaRenderMethod { pv: self.pv.clone() })
    }
}
```

Usage in templates:
- {{ value.render('json') }}
- {{ value.render('compact') }}
- {{ value.render('yaml') }}

The style argument is a call-site override - takes precedence over type-level renderers.
